export function resolveAmblastLegacyPageSlug(slug: string | null | undefined): AmblastLegacyPageSlug {
  const normalized = (slug ?? "index").trim().replace(/^\/+|\/+$/g, "") || "index"
  if (normalized === "over-ons" || normalized === "diensten" || normalized === "portfolio" || normalized === "contact") return normalized
  return "index"
}
